package agent

import (
	"context"
	"fmt"
	"regexp"
	"strings"

	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// AttemptIntegrityPreserveReason is the canonical landing Reason written when
// DDx rejects an otherwise-clean attempt because it violated the execute-bead
// integrity contract (post-commit mutation, empty pre-commit gate evidence, or
// uncommitted changes after the implementation commit). ClassifyExecuteBeadStatus
// and classifyLandingFailureMode match on this exact string to route the
// attempt to preserved_needs_review + FailureModeAttemptIntegrity rather than
// letting it land as success. The specific human explanation lives in the
// result's Error field; this constant is the stable machine marker.
const AttemptIntegrityPreserveReason = "execute-bead integrity violation"

// CommitEvent is one HEAD-moving entry parsed from a worktree's reflog. Action
// is the leading verb of the reflog message ("commit", "commit (amend)",
// "commit (initial)", "rebase (finish)", "checkout", ...); SHA is the commit
// the entry pointed HEAD at.
type CommitEvent struct {
	SHA     string
	Action  string
	Subject string
}

// PreCommitGateRun captures one invocation of a pre-commit gate (e.g.
// `lefthook run pre-commit`) and the output it produced, so DDx can tell a
// meaningful staged-file gate from a no-op "no staged files" run.
type PreCommitGateRun struct {
	Command string
	Output  string
}

// AttemptIntegrityInput is the structured snapshot the post-agent validation
// step compares before marking an attempt successful: the commit events the
// agent produced, the final implementation revision, the worktree dirty state,
// and the pre-commit gate evidence. See ValidateAttemptIntegrity.
type AttemptIntegrityInput struct {
	BaseRev           string
	ImplementationRev string
	CommitEvents      []CommitEvent
	DirtyPaths        []string
	// CodeChanging is true when the attempt produced an implementation commit,
	// i.e. the bead changed tracked files and the gate/dirty contracts apply.
	CodeChanging bool
	GateRuns     []PreCommitGateRun
}

// AttemptIntegrityVerdict is the result of ValidateAttemptIntegrity. OK is true
// when the attempt satisfies the integrity contract. When OK is false, Reason
// is a short machine code and Detail is an operator-facing explanation that
// makes clear the rejection came from DDx validation, not from an
// implementation/agent failure.
type AttemptIntegrityVerdict struct {
	OK     bool
	Reason string
	Detail string
}

// Integrity reason codes (the Reason field of AttemptIntegrityVerdict).
const (
	IntegrityReasonPostCommitMutation = "post_commit_mutation"
	IntegrityReasonEmptyGateEvidence  = "empty_gate_evidence"
	IntegrityReasonDirtyAfterCommit   = "dirty_after_commit"
)

// reflogLineRe matches a `git reflog show HEAD` line:
//
//	<sha> HEAD@{N}: <message>
var reflogLineRe = regexp.MustCompile(`^(\S+)\s+HEAD@\{\d+\}:\s+(.*)$`)

// ParseHeadReflog parses `git reflog show HEAD` output lines (newest-first, as
// git emits them) into CommitEvents ordered oldest-first, so callers can reason
// about the first commit an agent made versus later rewrites. Lines that do not
// match the reflog shape are skipped.
func ParseHeadReflog(lines []string) []CommitEvent {
	var newestFirst []CommitEvent
	for _, line := range lines {
		line = strings.TrimRight(line, "\r")
		m := reflogLineRe.FindStringSubmatch(strings.TrimSpace(line))
		if m == nil {
			continue
		}
		sha := m[1]
		message := m[2]
		action := message
		subject := ""
		if idx := strings.Index(message, ": "); idx >= 0 {
			action = message[:idx]
			subject = message[idx+2:]
		}
		newestFirst = append(newestFirst, CommitEvent{
			SHA:     sha,
			Action:  strings.TrimSpace(action),
			Subject: strings.TrimSpace(subject),
		})
	}
	// Reverse to oldest-first.
	out := make([]CommitEvent, 0, len(newestFirst))
	for i := len(newestFirst) - 1; i >= 0; i-- {
		out = append(out, newestFirst[i])
	}
	return out
}

// classifyLefthookOutput buckets a single pre-commit gate run's output as
// "meaningful" (at least one hook actually executed against staged files),
// "no_staged_files" (the run was a no-op because nothing was staged), or
// "unknown" (neither signal present). The no_staged_files markers mirror the
// phrasing lefthook and the execute-bead prompt use for an empty staged set.
func classifyLefthookOutput(output string) string {
	lower := strings.ToLower(output)
	noStaged := containsAny(lower,
		"no files for inspection",
		"no staged files",
		"no matching staged files",
		"no-staged-files",
		"no files to inspect",
		"no files matched",
	)
	// "executed in" / the success glyphs / "running hook" only appear when a
	// hook actually ran. Note: "summary: (skip)" is NOT a meaningful marker —
	// lefthook prints it for no-op runs — so it is deliberately excluded.
	meaningful := containsAny(lower,
		"executed in",
		"✔",
		"✓",
		"❯",
		"running hook",
	)
	switch {
	case meaningful:
		return "meaningful"
	case noStaged:
		return "no_staged_files"
	default:
		return "unknown"
	}
}

// ValidateAttemptIntegrity performs the structured post-agent integrity check.
// It is pure so it can be exercised directly by regression tests that simulate
// an execute-bead transcript. It rejects an attempt when:
//
//   - the implementation commit was amended or replaced after the first commit
//     (post-commit mutation), comparing the first commit event against the final
//     implementation revision;
//   - the bead changed code but every observed pre-commit gate run reported no
//     staged files, so the gate never tested the committed change;
//   - the bead changed code but tracked files remained uncommitted after the
//     implementation commit.
//
// Checks that lack evidence (no commit events observed, no gate runs captured)
// are skipped rather than failed, so the validator never rejects an attempt it
// could not actually observe.
func ValidateAttemptIntegrity(in AttemptIntegrityInput) AttemptIntegrityVerdict {
	if mutated, detail := detectPostCommitMutation(in.CommitEvents, in.ImplementationRev); mutated {
		return AttemptIntegrityVerdict{
			Reason: IntegrityReasonPostCommitMutation,
			Detail: detail,
		}
	}

	if in.CodeChanging && len(in.GateRuns) > 0 {
		sawMeaningful := false
		sawNoStaged := false
		for _, run := range in.GateRuns {
			switch classifyLefthookOutput(run.Output) {
			case "meaningful":
				sawMeaningful = true
			case "no_staged_files":
				sawNoStaged = true
			}
		}
		if !sawMeaningful && sawNoStaged {
			return AttemptIntegrityVerdict{
				Reason: IntegrityReasonEmptyGateEvidence,
				Detail: "DDx validation: every pre-commit gate run reported no staged files, so the required pre-commit gate never tested the committed change; this is not acceptance evidence. Detected by DDx, not an implementation failure.",
			}
		}
	}

	if in.CodeChanging && len(in.DirtyPaths) > 0 {
		return AttemptIntegrityVerdict{
			Reason: IntegrityReasonDirtyAfterCommit,
			Detail: fmt.Sprintf("DDx validation: tracked files remained uncommitted after the implementation commit (%s); the contract requires a clean worktree. Detected by DDx, not an implementation failure.", strings.Join(in.DirtyPaths, ", ")),
		}
	}

	return AttemptIntegrityVerdict{OK: true}
}

// detectPostCommitMutation reports whether the agent rewrote its implementation
// commit after the first commit. It returns true when more than one commit
// event is present and either an amend appears after the first commit or the
// first commit's SHA differs from the final implementation revision. A single
// commit whose SHA matches the implementation revision is clean.
func detectPostCommitMutation(events []CommitEvent, implementationRev string) (bool, string) {
	var commits []CommitEvent
	for _, ev := range events {
		if strings.HasPrefix(ev.Action, "commit") {
			commits = append(commits, ev)
		}
	}
	if len(commits) < 2 {
		return false, ""
	}
	first := commits[0]
	hasAmend := false
	for _, c := range commits[1:] {
		if strings.Contains(c.Action, "amend") {
			hasAmend = true
			break
		}
	}
	replaced := implementationRev != "" && first.SHA != "" && !shaEqual(first.SHA, implementationRev)
	if !hasAmend && !replaced {
		return false, ""
	}
	detail := fmt.Sprintf(
		"DDx validation: the implementation commit was rewritten after the first commit (%d commit events; first %s, final implementation_rev %s). The execute-bead contract requires exactly one commit with no post-commit amend/rebase. Detected by DDx, not an implementation failure; rerun the bead in a fresh attempt.",
		len(commits), shortSHA(first.SHA), shortSHA(implementationRev),
	)
	return true, detail
}

// shaEqual reports whether two git revisions refer to the same commit, allowing
// for one side being an abbreviation of the other.
func shaEqual(a, b string) bool {
	a = strings.TrimSpace(a)
	b = strings.TrimSpace(b)
	if a == "" || b == "" {
		return false
	}
	if a == b {
		return true
	}
	if len(a) < 7 || len(b) < 7 {
		return false
	}
	if len(a) < len(b) {
		return strings.HasPrefix(b, a)
	}
	return strings.HasPrefix(a, b)
}

func shortSHA(sha string) string {
	sha = strings.TrimSpace(sha)
	if len(sha) > 12 {
		return sha[:12]
	}
	if sha == "" {
		return "(none)"
	}

	detail := strings.TrimSpace(firstNonEmpty(report.Detail, report.Error))
	if detail == "" && err != nil {
		detail = strings.TrimSpace(err.Error())
	}
	if loopMode == executeloop.ModeWatch && runtime.ProjectRoot != "" {
		preserveDirty := w.preDispatchDirtyPreserver
		if preserveDirty == nil {
			preserveDirty = preservePreDispatchDirtyPaths
		}
		if preserved, preserveErr := preserveDirty(runtime.ProjectRoot, checkpointDirty.DirtyPaths); preserveErr == nil && preserved != nil {
			if runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log,
					"preserved pre-dispatch implementation changes in %s under %s; released %s and continuing watch. dirty paths: %s. recover with %s\n",
					runtime.ProjectRoot,
					preserved.PreserveRef,
					candidate.ID,
					strings.Join(preserved.DirtyPaths, ", "),
					preserved.RecoverCommand,
				)
			}
			emit("loop.pre_dispatch_dirty_preserved", map[string]any{
				"reason":          checkpointDirty.Reason,
				"bead_id":         candidate.ID,
				"project_root":    runtime.ProjectRoot,
				"dirty_paths":     preserved.DirtyPaths,
				"preserve_ref":    preserved.PreserveRef,
				"recover_command": preserved.RecoverCommand,
				"detail":          detail,
			})
			return executeBeadIterationOutcome{Continue: true}, nil
		}
	}
	result.OperatorAttention = checkpointDirty
	setExit("OperatorAttention", "operator_attention")
	if runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log,
			"operator attention: project worktree %s has uncommitted implementation changes; released %s. %s\n",
			checkpointDirty.ProjectRoot,
			candidate.ID,
			checkpointDirty.Message,
		)
	}
	emit("loop.operator_attention", map[string]any{
		"reason":       checkpointDirty.Reason,
		"bead_id":      candidate.ID,
		"project_root": checkpointDirty.ProjectRoot,
		"dirty_paths":  checkpointDirty.DirtyPaths,
		"message":      checkpointDirty.Message,
		"detail":       detail,
	})
	return executeBeadIterationOutcome{Stop: true}, nil
}
if IsResourceExhaustedStatus(report.Status) {
	result.Attempts++
	setExit("ResourceExhausted", "resource_exhausted")
	if err := releaseWorkerClaim(w.Store, candidate.ID, assignee); err != nil {
		_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
			return commitOutcomeError("Unclaim", assignee, result, err)
		})
		if ctx.Err() != nil {
			return executeBeadIterationOutcome{Stop: true}, ctx.Err()
		}
		return executeBeadIterationOutcome{Stop: true}, err
	}
	emitResourceExhausted(emit, w.Store, candidate.ID, report, assignee, now().UTC())
	result.Results = append(result.Results, report)
	result.Failures++
	result.LastFailureStatus = report.Status
	if err := w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC())); err != nil {
		_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
			return commitOutcomeError("AppendEvent", assignee, result, err)
		})
		if ctx.Err() != nil {
			return executeBeadIterationOutcome{Stop: true}, ctx.Err()
		}
		return executeBeadIterationOutcome{Stop: true}, err
	}
	if finalizeDurableAuditOrStop(candidate.ID, report) {
		return executeBeadIterationOutcome{Stop: true}, nil
	}
	finalAttemptID := report.AttemptID
	if finalAttemptID == "" {
		finalAttemptID = provAttemptID
	}
	phaseSeq++
	emitProgress(runtime.ProgressCh, ProgressEvent{
		EventID:   "evt-" + randomProgressID(),
		AttemptID: finalAttemptID,
		WorkerID:  runtime.WorkerID,
		ProjectID: runtime.ProjectRoot,
		BeadID:    candidate.ID,
		Harness:   harness,
		Model:     model,
		Profile:   profile,
		Phase:     "failed",
		PhaseSeq:  phaseSeq,
		Heartbeat: false,
		TS:        now().UTC(),
		ElapsedMS: now().Sub(runStart).Milliseconds(),
		Message:   report.Detail,
	})
	emit("bead.result", map[string]any{
		"bead_id":              candidate.ID,
		"status":               report.Status,
		"detail":               report.Detail,
		"session_id":           report.SessionID,
		"result_rev":           report.ResultRev,
		"base_rev":             report.BaseRev,
		"preserve_ref":         report.PreserveRef,
		"no_changes_rationale": report.NoChangesRationale,
		"duration_ms":          now().Sub(runStart).Milliseconds(),
	})
	if runtime.Log != nil {
		_, _ = fmt.Fprintln(runtime.Log, ResourceExhaustedStopMessage)
	}
	return executeBeadIterationOutcome{Stop: true}, nil
}
if isRoutingInfrastructureReport(report) {
	result.Attempts++
	report.OutcomeReason = FailureModeNoViableProvider
	report.Disrupted = true
	report.DisruptionReason = "routing"
	serverOutageActivated := false
	if activated, _ := serverOutage.Record(report, candidate.ID, now().UTC()); activated {
		serverOutageActivated = true
		pausedInfraUntil = time.Time{}
	}
	if err := releaseWorkerClaim(w.Store, candidate.ID, assignee); err != nil {
		_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
			return commitOutcomeError("Unclaim", assignee, result, err)
		})
		if ctx.Err() != nil {
			return executeBeadIterationOutcome{Stop: true}, ctx.Err()
		}
		return executeBeadIterationOutcome{Stop: true}, err
	}
	emitDisruptionDetected(emit, w.Store, candidate.ID,
		report.DisruptionReason, report.Detail, report.Harness, report.Model, assignee, now().UTC())
	appendExecutionRoutingIntentEvidence(w.Store, candidate, report, now().UTC())
	result.Results = append(result.Results, report)
	result.Failures++
	result.LastFailureStatus = report.Status
	if err := w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC())); err != nil {
		_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
			return commitOutcomeError("AppendEvent", assignee, result, err)
		})
		if ctx.Err() != nil {
			return executeBeadIterationOutcome{Stop: true}, ctx.Err()
		}
		return executeBeadIterationOutcome{Stop: true}, err
	}
	if finalizeDurableAuditOrStop(candidate.ID, report) {
		return executeBeadIterationOutcome{Stop: true}, nil
	}
	finalAttemptID := report.AttemptID
	if finalAttemptID == "" {
		finalAttemptID = provAttemptID
	}
	phaseSeq++
	emitProgress(runtime.ProgressCh, ProgressEvent{
		EventID:   "evt-" + randomProgressID(),
		AttemptID: finalAttemptID,
		WorkerID:  runtime.WorkerID,
		ProjectID: runtime.ProjectRoot,
		BeadID:    candidate.ID,
		Harness:   harness,
		Model:     model,
		Profile:   profile,
		Phase:     "failed",
		PhaseSeq:  phaseSeq,
		Heartbeat: false,
		TS:        now().UTC(),
		ElapsedMS: now().Sub(runStart).Milliseconds(),
		Message:   report.Detail,
	})
	emit("bead.result", map[string]any{
		"bead_id":              candidate.ID,
		"status":               report.Status,
		"detail":               report.Detail,
		"session_id":           report.SessionID,
		"result_rev":           report.ResultRev,
		"base_rev":             report.BaseRev,
		"preserve_ref":         report.PreserveRef,
		"no_changes_rationale": report.NoChangesRationale,
		"duration_ms":          now().Sub(runStart).Milliseconds(),
	})
	if runtime.Log != nil {
		_, _ = fmt.Fprintln(runtime.Log, formatLoopResultLine(candidate.ID, report))
	}
	// In watch mode a single bead that cannot route (no_viable_provider)
	// must not terminate an otherwise-healthy long-running drain
	// (ddx-a827d07f): skip it for the rest of the pass and keep draining
	// other ready beads. The bead is left open and untouched (no
	// park/cooldown) so it stays immediately re-claimable; the in-memory
	// skip clears when the queue next drains empty, giving routing a
	// fresh retry. Once and drain modes retain the existing
	// stop-on-routing-failure contract.
	if loopMode == executeloop.ModeWatch {
		if !serverOutageActivated {
			transientCandidateSkips[candidate.ID] = routingUnavailableSkipReason
		}
		return executeBeadIterationOutcome{Continue: true}, nil
	}
	setExit("RoutingUnavailable", "routing_unavailable")
	return executeBeadIterationOutcome{Stop: true}, nil
}
// Per-bead cost budget exhausted: unclaim the bead (immediately
// re-claimable), emit the TD-031 §5 per-bead-budget-exhausted event,
// and increment the consecutive_ladder_exhaustions counter so the
// auto-recovery hook (sister bead ddx-63155d5c) can fire when the
// threshold is exceeded. No cooldown is set per ADR-024 Per-Bead Budget.
if isPerBeadBudgetExhaustedReport(report) {
	result.Attempts++
	if err := releaseWorkerClaim(w.Store, candidate.ID, assignee); err != nil {
		_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
			return commitOutcomeError("Unclaim", assignee, result, err)
		})
		if ctx.Err() != nil {
			return executeBeadIterationOutcome{Stop: true}, ctx.Err()
		}
		return executeBeadIterationOutcome{Stop: true}, err
	}
	_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
		Kind:      "per-bead-budget-exhausted",
		Summary:   "per-bead cost budget exhausted; bead returned to open without cooldown",
		Body:      fmt.Sprintf("total_cost=%.4f\n%s", report.CostUSD, report.Detail),
		Actor:     assignee,
		Source:    "ddx work",
		CreatedAt: now().UTC(),
	})
	_ = incrementConsecutiveLadderExhaustions(ctx, w.Store, candidate.ID)
	if updated, getErr := w.Store.Get(ctx, candidate.ID); getErr == nil &&
		consecutiveLadderExhaustionsValue(updated.Extra[consecutiveLadderExhaustionsKey]) >= 2 {
		hasManualLabel := false
		for _, lbl := range candidate.Labels {
			if lbl == "recovery:manual" {
				hasManualLabel = true
				break
			}
		}
		if hasManualLabel {
			_ = parkToProposedSimple(w.Store, candidate.ID, bead.ParkLadderExhaustionManual, "recovery:manual label set", now().UTC())
		} else if runtime.PostLadderExhaustionHook != nil {
			failureClass := deriveRecoveryFailureClass(report)
			_, _ = runtime.PostLadderExhaustionHook(ctx, candidate.ID, failureClass)
		}
	}
	if err := w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC())); err != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "outcome store error (AppendEvent %s): %v (continuing)\n", candidate.ID, err)
		}
	}
	result.Results = append(result.Results, report)
	result.Failures++
	result.LastFailureStatus = report.Status
	if finalizeDurableAuditOrStop(candidate.ID, report) {
		return executeBeadIterationOutcome{Stop: true}, nil
	}
	emit("bead.result", map[string]any{
		"bead_id":              candidate.ID,
		"status":               report.Status,
		"detail":               report.Detail,
		"session_id":           report.SessionID,
		"result_rev":           report.ResultRev,
		"base_rev":             report.BaseRev,
		"preserve_ref":         report.PreserveRef,

package agent

// execute_bead_dangling_success.go — detection and recovery for
// dangling-success beads (ddx-2b2d114e, ddx-f1e7dfdf).
//
// A "dangling success" is an in_progress bead whose most recent execution
// produced outcome=task_succeeded and a non-empty result_rev, but the
// bead-close step (CloseWithEvidence) never ran — typically because the
// process crashed between Land() and the store write.
//
// Two sub-cases:
//   A. result_rev IS reachable from HEAD (merge succeeded, close didn't).
//      Recovery: call CloseWithEvidence directly; no re-execution needed.
//   B. result_rev is NOT reachable from HEAD (crash during Land / dangling
//      commit). Recovery: preserve the successful commit under
//      refs/ddx/iterations/... when the object still exists locally, or park
//      the bead for operator attention when DDx cannot recover the commit.

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// DanglingSuccessFinding describes a bead whose last successful execution was
// not finalized. Returned by DetectDanglingSuccessBeads.
type DanglingSuccessFinding struct {
	// BeadID is the bead that stalled.
	BeadID string `json:"bead_id"`
	// AttemptID is the attempt whose result.json shows task_succeeded.
	AttemptID string `json:"attempt_id"`
	// ResultRev is the commit SHA the agent produced.
	ResultRev string `json:"result_rev"`
	// Reachable is true when ResultRev is already merged into the target branch.
	// When true the bead can be closed idempotently.
	// When false the merge itself was lost and manual intervention is required.
	Reachable bool `json:"reachable"`
	// ResultFile is the absolute path to the result.json artifact.
	ResultFile string `json:"result_file"`
}

type danglingSuccessOutcome string

const (
	danglingSuccessOutcomeClosed           danglingSuccessOutcome = "closed"
	danglingSuccessOutcomePreserved        danglingSuccessOutcome = "preserved"
	danglingSuccessOutcomeOperatorRequired danglingSuccessOutcome = "operator_required"
)

// DanglingSuccessRecovery is the terminal decision for a previously successful
// attempt. Any non-nil result means the caller must skip a fresh execution.
type DanglingSuccessRecovery struct {
	Outcome       danglingSuccessOutcome
	AttemptID     string
	BaseRev       string
	ResultRev     string
	PreserveRef   string
	FailureReason string
	SessionID     string
}

// latestTaskSucceededResult scans .ddx/executions/ for the most recent
// result.json that belongs to beadID and has outcome=task_succeeded with a
// non-empty result_rev. Returns nil when no such entry is found.
//
// The scan is intentionally cheap (directory listing + JSON decode per dir);
// it only runs when the work loop has already claimed a bead and is checking
// whether a prior successful attempt must be reconciled before retry.
func latestTaskSucceededResult(projectRoot, beadID string) *ExecuteBeadResult {
	execDir := executeBeadArtifactRoot(projectRoot)
	entries, err := os.ReadDir(execDir)
	if err != nil {
		return nil
	}

	// Attempt IDs are formatted as 20060102T150405-<hex>, so lexicographic
	// descending order gives us newest first.
	// We want the newest entry that matches beadID and task_succeeded.
	for i := len(entries) - 1; i >= 0; i-- {
		entry := entries[i]
		if !entry.IsDir() {
			continue
		}
		resultPath := filepath.Join(execDir, entry.Name(), "result.json")
		data, err := os.ReadFile(resultPath)
		if err != nil {
			continue
		}
		var res ExecuteBeadResult
		if err := json.Unmarshal(data, &res); err != nil {
			continue
		}
		if res.BeadID != beadID {
			continue
		}
		if res.Outcome != ExecuteBeadOutcomeTaskSucceeded {
			continue
		}
		if res.ResultRev == "" || res.ResultRev == res.BaseRev {
			continue
		}
		// Found a valid prior success.
		return &res
	}
	return nil
}

// isRevReachableFromHead returns true when rev is reachable from the HEAD of
// the given directory (i.e., `git merge-base --is-ancestor rev HEAD` exits 0).
// Returns false on any error.
func isRevReachableFromHead(projectRoot, rev string) bool {
	if rev == "" || projectRoot == "" {
		return false
	}
	err := internalgit.Command(context.Background(), projectRoot, "merge-base", "--is-ancestor", rev, "HEAD").Run()
	return err == nil
}

func isCommitObjectPresent(projectRoot, rev string) bool {
	if rev == "" || projectRoot == "" {
		return false
	}
	err := internalgit.Command(context.Background(), projectRoot, "cat-file", "-e", rev+"^{commit}").Run()
	return err == nil
}

// DetectDanglingSuccessBeads scans all in_progress beads in the store and
// returns findings for any that have a prior task_succeeded result. Called by
// ddx bead doctor --dangling to surface operator-actionable cases.
//
// For each in_progress bead:
//   - scan .ddx/executions/ for a task_succeeded result.json
//   - check whether result_rev is reachable from HEAD
//   - report a DanglingSuccessFinding with Reachable=true/false
func DetectDanglingSuccessBeads(projectRoot string) ([]DanglingSuccessFinding, error) {
	execDir := executeBeadArtifactRoot(projectRoot)

	entries, err := os.ReadDir(execDir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("reading executions dir: %w", err)
	}

	// Index all task_succeeded results by bead_id → newest entry.
	type candidateEntry struct {
		res        ExecuteBeadResult
		resultFile string
	}
	byBead := make(map[string]candidateEntry)
	for i := len(entries) - 1; i >= 0; i-- {
		entry := entries[i]
		if !entry.IsDir() {
			continue
		}
		resultPath := filepath.Join(execDir, entry.Name(), "result.json")
		data, err := os.ReadFile(resultPath)
		if err != nil {
			continue
		}
		var res ExecuteBeadResult
		if err := json.Unmarshal(data, &res); err != nil {
			continue
		}
		if res.Outcome != ExecuteBeadOutcomeTaskSucceeded {
			continue
		}
		if res.ResultRev == "" || res.ResultRev == res.BaseRev {
			continue
		}
		if _, seen := byBead[res.BeadID]; !seen {
			byBead[res.BeadID] = candidateEntry{res: res, resultFile: resultPath}
		}
	}
	if len(byBead) == 0 {
		return nil, nil
	}

	// Read the tracker to find in_progress beads.
	beadsPath := ddxroot.JoinProject(projectRoot, "beads.jsonl")
	raw, err := os.ReadFile(beadsPath)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("reading beads.jsonl: %w", err)
	}

	var findings []DanglingSuccessFinding
	for _, line := range strings.Split(string(raw), "\n") {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		var b struct {
			ID     string `json:"id"`
			Status string `json:"status"`
		}
		if err := json.Unmarshal([]byte(line), &b); err != nil {
			continue
		}
		if b.Status != "in_progress" {
			continue
		}
		cand, ok := byBead[b.ID]
		if !ok {
			continue
		}
		reachable := isRevReachableFromHead(projectRoot, cand.res.ResultRev)
		findings = append(findings, DanglingSuccessFinding{
			BeadID:     b.ID,
			AttemptID:  cand.res.AttemptID,
			ResultRev:  cand.res.ResultRev,
			Reachable:  reachable,
			ResultFile: cand.resultFile,
		})
	}
	return findings, nil
}

func appendDanglingSuccessEvent(store ExecuteBeadLoopStore, beadID string, event bead.BeadEvent) {
	if store == nil || beadID == "" {
		return
	}
