// BuildLandingGateContext prepares the inputs the gate evaluator needs to
// score a worker's result before LandBeadResult decides merge-vs-preserve:
//
//  1. Pin res.ResultRev to refs/ddx/gate-pins/<beadID>/<attemptID>
//     so the SHA stays alive while the ephemeral worktree exists.
//  2. WorktreeAdd a temp worktree under the configured DDx execution scratch
//     root at the pinned ref so gate evaluators can read the
//     result tree without disturbing the main worktree.
//  3. Read the worker manifest from that result tree and extract governing IDs.
//     When the manifest declares no governing IDs the temporary worktree is
//     removed immediately and the caller skips gate evaluation.
//
// The returned cleanup closure removes the worktree and deletes the pin ref.
// Callers MUST defer cleanup() before returning to avoid orphaned worktrees.
//
// On any error the function attempts to roll back partial state (pin+remove)
// and returns ("", nil, noop, err).
func BuildLandingGateContext(projectRoot string, res *ExecuteBeadResult, gitOps GitOps) (wtPath string, governIDs []string, cleanup func(), err error) {
	noop := func() {}

	if res == nil || res.ManifestFile == "" {
		return "", nil, noop, nil
	}
	if res.ResultRev == "" {
		return "", nil, noop, fmt.Errorf("BuildLandingGateContext: ResultRev empty, cannot pin")
	}

	// Pin ResultRev so the worktree-add target stays alive even though the worker
	// worktree was removed. Use bead+attempt to avoid collisions across attempts.
	attemptKey := res.AttemptID
	if attemptKey == "" {
		attemptKey = NowFunc().UTC().Format("20060102T150405Z")
	}
	pinRef := fmt.Sprintf("refs/ddx/gate-pins/%s/%s", res.BeadID, attemptKey)
	if upErr := gitOps.UpdateRef(projectRoot, pinRef, res.ResultRev); upErr != nil {
		return "", nil, noop, fmt.Errorf("pin ResultRev: %w", upErr)
	}
	unpin := func() { _ = gitOps.DeleteRef(projectRoot, pinRef) }

	wt, mkErr := config.MkdirExecutionScratch(projectRoot, "ddx-gate-wt-"+attemptKey+"-")
	if mkErr != nil {
		unpin()
		return "", nil, noop, fmt.Errorf("create temp worktree dir: %w", mkErr)
	}
	// os.MkdirTemp creates the directory, but `git worktree add` refuses to
	// run when the target already exists. Remove it so git can recreate it.
	_ = os.RemoveAll(wt)
	if addErr := gitOps.WorktreeAdd(projectRoot, wt, res.ResultRev); addErr != nil {
		_ = os.RemoveAll(wt)
		unpin()
		return "", nil, noop, fmt.Errorf("worktree add at %s: %w", res.ResultRev, addErr)
	}

	cleanup = func() {
		_ = gitOps.WorktreeRemove(projectRoot, wt)
		_ = os.RemoveAll(wt) // belt-and-suspenders if WorktreeRemove failed
		unpin()
	}

	manifestPath := filepath.Join(wt, filepath.FromSlash(res.ManifestFile))
	if _, statErr := os.Stat(manifestPath); statErr != nil {
		manifestPath = filepath.Join(projectRoot, filepath.FromSlash(res.ManifestFile))
	}
	if _, statErr := os.Stat(manifestPath); statErr != nil {
		cleanup()
		return "", nil, noop, nil
	}
	ids := ExtractGoverningIDsFromManifest(manifestPath)
	if len(ids) == 0 {
		cleanup()
		return "", nil, noop, nil
	}
	return wt, ids, cleanup, nil
}

// EvaluateRequiredGatesForResult is the canonical "run gate evaluation and
// write the bundle artifacts" sequence used by LandBeadResult and by upstream
// callers (server work) that want gate eval before submitting through
// the coordinator. It delegates to evaluateRequiredGates for the actual gate
// scoring, then mutates res to set GateResults, RequiredExecSummary,
// RatchetEvidence, and RatchetSummary, and writes checks.json into the
// execution bundle. Returns (anyRequiredFailed, ratchetFailed, err).
//
// When wtPath is empty or no governing IDs are provided, gate evaluation is
// skipped and res.RequiredExecSummary is set to "skipped" (matching
// summarizeGates behavior). checksArtifactPath, when non-empty and gate
// results exist, is the absolute path checks.json is written to;
// checksArtifactRel is the bundle-relative path stored in res.ChecksFile on
// successful write.
func EvaluateRequiredGatesForResult(wtPath string, governIDs []string, res *ExecuteBeadResult, projectRoot string, checksArtifactPath, checksArtifactRel string) (anyRequiredFailed bool, ratchetFailed bool, err error) {
	if res == nil {
		return false, false, fmt.Errorf("EvaluateRequiredGatesForResult: res is nil")
	}

	var gateResults []GateCheckResult
	var anyGateFailed, anyRatchetFailed bool
	if wtPath != "" && len(governIDs) > 0 {
		var gerr error
		gateResults, anyGateFailed, anyRatchetFailed, gerr = evaluateRequiredGates(wtPath, governIDs)
		if gerr != nil {
			return false, false, fmt.Errorf("evaluating required gates: %w", gerr)
		}
	}

	res.GateResults = gateResults
	res.RequiredExecSummary = summarizeGates(gateResults, anyGateFailed)
	res.RatchetEvidence = collectRatchetEvidence(gateResults)
	res.RatchetSummary = summarizeRatchets(res.RatchetEvidence)

	// Write checks.json when gate evaluation produced results and a path was
	// provided. Best-effort: a write failure leaves res.ChecksFile empty but
	// does not abort the gate evaluation.
	if len(gateResults) > 0 && checksArtifactPath != "" {
		checks := executeBeadChecks{
			AttemptID:       res.AttemptID,
			EvaluatedAt:     time.Now().UTC(),
			Summary:         res.RequiredExecSummary,
			Results:         gateResults,
			RatchetSummary:  res.RatchetSummary,
			RatchetEvidence: res.RatchetEvidence,
		}
		if writeErr := writeArtifactJSON(checksArtifactPath, checks); writeErr == nil {
			res.ChecksFile = checksArtifactRel
		}
	}

	return anyGateFailed, anyRatchetFailed, nil
}

	return mergeSHA, nil
}

// shortAttempt returns a 10-char slug derived from attemptID for use in temp
// branch names. When attemptID is empty, it returns the current timestamp.
func shortAttempt(attemptID string) string {
	if attemptID != "" {
		if len(attemptID) > 16 {
			return attemptID[:16]
		}
		return attemptID
	}
	return NowFunc().UTC().Format("20060102T150405")
}

// ApplyLandResultToExecuteBeadResult maps a LandResult onto an
// ExecuteBeadResult so the execute-bead loop sees the correct final status.
// It is the coordinator-pattern replacement for ApplyLandingToResult.
func ApplyLandResultToExecuteBeadResult(res *ExecuteBeadResult, land *LandResult) {
	if land == nil || res == nil {
		return
	}
	if land.TargetBranch != "" {
		res.TargetBranch = land.TargetBranch
	}
	switch land.Status {
	case "landed":
		// Fast-forward or merge commit — either way the target branch now
		// contains the worker's result. ResultRev's own parent is still
		// BaseRev so replay fidelity is preserved.
		reason := ""
		res.PreserveRef = ""
		if land.Merged {
			reason = "merged onto current tip"
		}
		if land.CheckoutSyncDeferred {
			detail := "checkout_sync_deferred"
			if len(land.CheckoutSyncDeferredPaths) > 0 {
				detail += ": " + strings.Join(land.CheckoutSyncDeferredPaths, ", ")
			}
			if reason == "" {
				reason = detail
			} else {
				reason += "; " + detail
			}
		}
		ApplyLandingToResult(res, &BeadLandingResult{Outcome: "merged", Reason: reason})
		landedTip := land.NewTip
		if land.LandedTip != "" {
			landedTip = land.LandedTip
		}
		// LandedTip reflects the ref that actually landed the implementation:
		// either ResultRev on the ff path or the merge commit SHA on the merge
		// path. A trailing final-result/evidence audit commit may advance NewTip
		// beyond this landed revision, but callers should keep ResultRev/LandedRev
		// pointing at the landed implementation state.
		if landedTip != "" {
			// Preserve the implementation rev before rewriting the compat alias.
			if res.ImplementationRev == "" {
				res.ImplementationRev = res.ResultRev
			}
			res.LandedRev = landedTip
			res.ResultRev = landedTip // backwards-compat alias mirrors LandedRev
		}
	case "preserved":
		res.Outcome = "preserved"
		res.Reason = land.Reason
		res.PreserveRef = land.PreserveRef
	case "no-changes":
		// Only overwrite when the worker itself did not already report
		// a richer no-changes rationale.
		if res.Outcome == "" || res.Outcome == ExecuteBeadOutcomeTaskSucceeded {
			ApplyLandingToResult(res, &BeadLandingResult{Outcome: "no-changes", Reason: land.Reason})
		} else if res.Reason == "" {
			res.Reason = land.Reason
		}
	}
	// Re-classify loop-visible status from the landing outcome.
	reasonForStatus := res.Reason
	if land.Status == "preserved" {
		// Only legacy/generic preserve reasons should fall back to
		// land_conflict. Safety gates preserve good output for operator
		// review and must not be reported as merge failures.
		if strings.HasPrefix(res.Reason, PreMergeChecksReason) ||
			isPreservedNeedsReviewReason(res.Reason) {
			reasonForStatus = res.Reason
		} else {
			reasonForStatus = "merge conflict"
		}
	}
	res.Status = ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, reasonForStatus)
	res.OrchestratorStatus = res.Status
	res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
}

