func TestLand_PostLandGateFailureRestoresTargetAndPreserves(t *testing.T) {
	r := newLandTestRepo(t)
	ops := RealLandingGitOps{}

	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature\n", "feat: feature")
	req := LandRequest{
